function ShaderBackground() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const gl = canvas.getContext("webgl");
    if (!gl) return;
    const resize = () => {
      canvas.width = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
      gl.viewport(0, 0, canvas.width, canvas.height);
    };
    resize();
    window.addEventListener("resize", resize);
    const vert = `attribute vec2 a_position; void main(){gl_Position=vec4(a_position,0,1);}`;
    const frag = `precision highp float;uniform vec2 u_res;uniform float u_time;
      float rnd(float x){return fract(sin(x)*1e4);}
      float rnd2(vec2 s){return fract(sin(dot(s,vec2(12.9898,78.233)))*43758.5453);}
      void main(){
        vec2 uv=(gl_FragCoord.xy*2.-u_res)/min(u_res.x,u_res.y);
        vec2 m=vec2(4.,2.);vec2 sc=vec2(256.);
        uv.x=floor(uv.x*sc.x/m.x)/(sc.x/m.x);
        uv.y=floor(uv.y*sc.y/m.y)/(sc.y/m.y);
        float t=u_time*.06+rnd(uv.x)*.4;float lw=.0008;
        vec3 col=vec3(0.);
        for(int j=0;j<3;j++)for(int i=0;i<5;i++){
          float fi=float(i);float fj=float(j);
          col[j]+=lw*fi*fi/abs(fract(t-.01*fj+fi*.01)-length(uv));
        }
        gl_FragColor=vec4(col[2]*.9+col[1]*.2,col[1]*.5+col[0]*.3,col[0]*1.1+col[2]*.4,1.);
      }`;
    const mk = (type, src) => { const s = gl.createShader(type); gl.shaderSource(s, src); gl.compileShader(s); return s; };
    const prog = gl.createProgram();
    gl.attachShader(prog, mk(gl.VERTEX_SHADER, vert));
    gl.attachShader(prog, mk(gl.FRAGMENT_SHADER, frag));
    gl.linkProgram(prog); gl.useProgram(prog);
    const buf = gl.createBuffer(); gl.bindBuffer(gl.ARRAY_BUFFER, buf);
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1,-1,1,-1,-1,1,1,1]), gl.STATIC_DRAW);
    const pos = gl.getAttribLocation(prog, "a_position");
    gl.enableVertexAttribArray(pos); gl.vertexAttribPointer(pos, 2, gl.FLOAT, false, 0, 0);
    const ur = gl.getUniformLocation(prog, "u_res");
    const ut = gl.getUniformLocation(prog, "u_time");
    let id, tm = 0;
    const render = () => { tm += .05; gl.uniform2f(ur, canvas.width, canvas.height); gl.uniform1f(ut, tm); gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4); id = requestAnimationFrame(render); };
    render();
    return () => { cancelAnimationFrame(id); window.removeEventListener("resize", resize); };
  }, []);
  return <canvas ref={canvasRef} style={{ position:"absolute", inset:0, width:"100%", height:"100%", display:"block" }} />;
}

