function SectionHeader({ title, sub }) {
  return (
    <div style={{ textAlign:"center", marginBottom:20 }}>
      <div style={{ fontFamily:"'Georgia',serif", fontSize:22, fontWeight:400, color:"#f5e8d0", letterSpacing:"2px", marginBottom:4 }}>{title}</div>
      <div style={{ fontSize:12, color:"rgba(201,169,110,0.7)", letterSpacing:"1px" }}>{sub}</div>
      <div style={{ ...styles.divider, marginTop:10 }} />
    </div>
  );
}

function BookingPage({ preselect }) {
  const [name, setName] = useState("");
  const [phone, setPhone] = useState("");
  const [service, setService] = useState(preselect || "");
  const [date, setDate] = useState("");
  const [slot, setSlot] = useState("");
  const [notes, setNotes] = useState("");
  const [done, setDone] = useState(false);
  const [err, setErr] = useState("");

  useEffect(() => { setService(preselect || ""); }, [preselect]);

  const submit = () => {
    if (!name || !phone || !service || !date || !slot) { setErr("يرجى تعبئة جميع الحقول واختيار الوقت ⚠"); return; }
    setErr(""); setDone(true);
  };

  const today = new Date().toISOString().split("T")[0];

  return (
    <div style={{ padding:"24px 28px 40px" }}>
      <SectionHeader title="حجز موعد" sub="✦ ملئي التفاصيل وسنتواصل معك ✦" />
      {!done ? (
        <>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:10 }}>
            <Field label="الاسم الكامل"><input style={styles.input} value={name} onChange={e => setName(e.target.value)} placeholder="اسمك هنا..." /></Field>
            <Field label="رقم الهاتف"><input style={styles.input} type="tel" value={phone} onChange={e => setPhone(e.target.value)} placeholder="07X XXXX XXXX" /></Field>
          </div>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:10 }}>
            <Field label="الخدمة">
              <select style={styles.input} value={service} onChange={e => setService(e.target.value)}>
                <option value="">اختاري الخدمة...</option>
                {SERVICES.map(s => <option key={s.name}>{s.name}</option>)}
              </select>
            </Field>
            <Field label="التاريخ"><input style={styles.input} type="date" min={today} value={date} onChange={e => setDate(e.target.value)} /></Field>
          </div>
          <Field label="اختاري الوقت">
            <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:6, marginTop:4 }}>
              {TIMES.map(t => {
                const busy = BUSY_TIMES.includes(t);
                return (
                  <div key={t} onClick={() => !busy && setSlot(t)}
                    style={{ background: slot===t ? "rgba(201,169,110,0.2)" : busy ? "rgba(255,255,255,0.02)" : "rgba(255,255,255,0.04)",
                      border: slot===t ? "0.5px solid #c9a96e" : "0.5px solid rgba(201,169,110,0.2)",
                      borderRadius:6, padding:"7px 4px", textAlign:"center", fontSize:11,
                      color: slot===t ? "#c9a96e" : busy ? "rgba(240,230,211,0.2)" : "rgba(240,230,211,0.6)",
                      cursor: busy ? "not-allowed" : "pointer", textDecoration: busy ? "line-through" : "none" }}>
                    {t}
                  </div>
                );
              })}
            </div>
          </Field>
          <Field label="ملاحظات إضافية" style={{ marginTop:10 }}>
            <textarea style={{ ...styles.input, resize:"none", height:70 }} value={notes} onChange={e => setNotes(e.target.value)} placeholder="أي معلومات تودين إضافتها..." />
          </Field>
          {err && <div style={{ color:"#f09595", fontSize:12, textAlign:"center", marginTop:8 }}>{err}</div>}
          <button onClick={submit} style={styles.submitBtn}>✦ تأكيد الحجز ✦</button>
        </>
      ) : (
        <motion.div initial={{ opacity:0, y:20 }} animate={{ opacity:1, y:0 }}
          style={{ background:"rgba(30,200,130,0.08)", border:"0.5px solid rgba(30,200,130,0.3)", borderRadius:14, padding:28, textAlign:"center" }}>
          <div style={{ fontSize:32, marginBottom:12 }}>✦</div>
          <div style={{ fontFamily:"'Georgia',serif", fontSize:18, color:"#8ee8c0", marginBottom:10 }}>تم استلام طلبك بنجاح!</div>
          <div style={{ fontSize:13, color:"rgba(240,230,211,0.6)", lineHeight:1.8 }}>
            مرحباً {name}! تم استلام حجزك لـ<span style={{ color:"#c9a96e" }}>{service}</span>
            <br />بتاريخ {date} — {slot}
            <br />سنتواصل على {phone} قريباً 🌸
          </div>
        </motion.div>
      )}
    </div>
  );
}

function Field({ label, children, style }) {
  return <div style={{ display:"flex", flexDirection:"column", gap:4, ...style }}><label style={styles.label}>{label}</label>{children}</div>;
}

