// ---- MAIN APP ----
export default function App() {
  const [page, setPage] = useState("home");
  const [preselect, setPreselect] = useState("");

  const pageMap = { home:"الرئيسية", services:"الخدمات", booking:"احجزي موعد", about:"عن العيادة", contact:"تواصلي" };

  return (
    <div style={styles.site}>
      <ShaderBackground />
      <div style={styles.vignette} />

      {/* NAV */}
      <nav style={styles.nav}>
        <div style={styles.navLogo} onClick={() => setPage("home")}>
          <img src={LOGO} alt="Aurora" style={{ width:36, height:36, borderRadius:"50%", objectFit:"cover", border:"0.5px solid rgba(201,169,110,0.4)" }} />
          <span style={{ fontFamily:"'Georgia',serif", fontSize:16, letterSpacing:"3px", color:"#c9a96e" }}>AURORA</span>
        </div>
        <div style={styles.navLinks}>
          {Object.entries(pageMap).map(([key, label]) => (
            <NavBtn key={key} active={page === key} onClick={() => setPage(key)}>{label}</NavBtn>
          ))}
        </div>
      </nav>

      {/* PAGES */}
      <div style={styles.page}>
        {page === "home" && <HomePage setPage={setPage} setPreselect={setPreselect} />}
        {page === "services" && <ServicesPage setPage={setPage} setPreselect={setPreselect} />}
        {page === "booking" && <BookingPage preselect={preselect} />}
        {page === "about" && <AboutPage />}
        {page === "contact" && <ContactPage setPage={setPage} />}
      </div>
    </div>
  );
}